1	export type Cell = [number, number];
2	
3	export const nextGeneration = (liveCells: Cell[]): Cell[] =>
4	  liveCells.filter(([x, y]) => {
5	    const liveNeighbors = liveCells.filter(
6	      ([nx, ny]) =>
7	        Math.abs(nx - x) <= 1 &&
8	        Math.abs(ny - y) <= 1 &&
9	        !(nx === x && ny === y),
10	    ).length;
11	    return liveNeighbors === 3;
12	  });
